def generate_saml_request():
    request_id = f"_{uuid.uuid4()}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = f'''<samlp:AuthnRequest 
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{IDP_SSO_URL}"
        AssertionConsumerServiceURL="{SP_ACS_URL}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{SP_ENTITY_ID}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    </samlp:AuthnRequest>'''
    
    return request_id, saml_request

def encode_saml_request(saml_request):
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    return encoded

def decode_saml_response(saml_response_b64):
    decoded = base64.b64decode(saml_response_b64)
    return decoded.decode('utf-8')

def parse_saml_response(saml_xml):
    try:
        root = ET.fromstring(saml_xml)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    assertion = root.find('.//saml:Assertion', SAML_NAMESPACES)
    
    if assertion is None:
        raise ValueError("No Assertion found in SAML response")
    
    return root, assertion

def extract_user_attributes(assertion):
    attributes = {}
    
    subject = assertion.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
    if subject is not None:
        attributes['NameID'] = subject.text
        name_id_format = subject.get('Format', '')
        if name_id_format:
            attributes['NameIDFormat'] = name_id_format
    
    attribute_statement = assertion.find('.//saml:AttributeStatement', SAML_NAMESPACES)
    
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('.//saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name', '')
            attr_friendly_name = attribute.get('FriendlyName', attr_name)
            
            attr_values = []
            for attr_value in attribute.findall('.//saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    attr_values.append(attr_value.text)
            
            if attr_values:
                if len(attr_values) == 1:
                    attributes[attr_friendly_name] = attr_values[0]
                else:
                    attributes[attr_friendly_name] = attr_values
    
    return attributes

def validate_assertion(assertion):
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        current_time = datetime.utcnow()
        
        if not_before:
            not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            if current_time < not_before_dt:
                raise ValueError("Assertion not yet valid")
        
        if not_on_or_after:
            not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            if current_time >= not_on_or_after_dt:
                raise ValueError("Assertion has expired")
        
        audience_restriction = conditions.find('.//saml:AudienceRestriction/saml:Audience', SAML_NAMESPACES)
        if audience_restriction is not None:
            audience = audience_restriction.text
            if audience != SP_ENTITY_ID:
                raise ValueError(f"Audience mismatch: expected {SP_ENTITY_ID}, got {audience}")
    
    return True

def validate_response_status(root):
    status_code = root.find('.//samlp:StatusCode', SAML_NAMESPACES)
    
    if status_code is not None:
        status_value = status_code.get('Value', '')
        if 'Success' not in status_value:
            status_message = root.find('.//samlp:StatusMessage', SAML_NAMESPACES)
            message = status_message.text if status_message is not None else 'Unknown error'
            raise ValueError(f"SAML Response status not successful: {status_value} - {message}")
    
    return True

@app.route('/')
def index():
    logged_in = 'user_attributes' in session
    user_attributes = session.get('user_attributes', {})
    
    return render_template_string(HOME_TEMPLATE, logged_in=logged_in, user_attributes=user_attributes)

@app.route('/saml/login')
def saml_login():
    request_id, saml_request = generate_saml_request()
    
    pending_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'relay_state': request.args.get('RelayState', '/')
    }
    
    encoded_request = encode_saml_request(saml_request)
    
    relay_state = request.args.get('RelayState', '/')
    
    redirect_url = f"{IDP_SSO_URL}?SAMLRequest={encoded_request}&RelayState={relay_state}"
    
    return redirect(redirect_url)

@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    try:
        saml_response_b64 = request.form.get('SAMLResponse')
        relay_state = request.form.get('RelayState', '/')
        
        if not saml_response_b64:
            return jsonify({'error': 'No SAMLResponse provided'}), 400
        
        saml_xml = decode_saml_response(saml_response_b64)
        
        root, assertion = parse_saml_response(saml_xml)
        
        validate_response_status(root)
        
        validate_assertion(assertion)
        
        user_attributes = extract_user_attributes(assertion)
        
        if not user_attributes:
            return jsonify({'error': 'No user attributes found in assertion'}), 400
        
        session.permanent = True
        session['user_attributes'] = user_attributes
        session['authenticated'] = True
        session['auth_time'] = datetime.utcnow().isoformat()
        session['session_id'] = secrets.token_hex(16)
        
        return redirect(relay_state)
        
    except ValueError as e:
        return jsonify({'error': f'SAML validation error: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': f'Error processing SAML response: {str(e)}'}), 500

@app.route('/saml/metadata')
def saml_metadata():
    metadata = f'''<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{SP_ENTITY_ID}">
    <md:SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:AssertionConsumerService 
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SP_ACS_URL}"
            index="0"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''
    
    return metadata, 200, {'Content-Type': 'application/xml'}

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/api/user')
def api_user():
    if 'user_attributes' not in session:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'authenticated': True,
        'user_attributes': session['user_attributes'],
        'auth_time': session.get('auth_time'),
        'session_id': session.get('session_id')
    })

@app.route('/protected')
def protected():
    if 'user_attributes' not in session:
        return redirect(url_for('saml_login', RelayState=request.url))
    
    return jsonify({
        'message': 'This is a protected resource',
        'user': session['user_attributes']
    })

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)